    def _select_tip_with_weights(self):
        """Select a tip key from TIPS, optionally biased by self.tip_weights.

        If self.tip_weights is None, falls back to a uniform draw via self.rng.choice().
        Otherwise, normalizes the (nonnegative) weights into a probability distribution
        and selects a key using self.rng.random() against the cumulative distribution.
        Missing weight entries default to 1.0; nonpositive weights are treated as 0.
        Falls back to uniform self.rng.choice() if all effective weights are zero.
        """
        tip_keys = list(TIPS.keys())

        if self.tip_weights is None:
            return self.rng.choice(tip_keys)

        weights = [max(self.tip_weights.get(key, 1.0), 0.0) for key in tip_keys]
        total_weight = sum(weights)

        if total_weight <= 0:
            return self.rng.choice(tip_keys)

        probabilities = [weight / total_weight for weight in weights]

        threshold = self.rng.random()
        cumulative = 0.0
        for key, probability in zip(tip_keys, probabilities):
            cumulative += probability
            if threshold < cumulative:
                return key

        # Guard against floating point rounding leaving threshold >= cumulative total.
        return tip_keys[-1]

